import 'package:cloud_firestore/cloud_firestore.dart'; import 'package:flutter/material.dart'; import '../services/firestore_service.dart';
class LocationsScreen extends StatelessWidget { const LocationsScreen({super.key}); @override Widget build(BuildContext context){ final service=FirestoreService(); return Scaffold(appBar: AppBar(title: const Text('Campus Navigation')), body: StreamBuilder<QuerySnapshot<Map<String,dynamic>>>(stream: service.streamCollection('locations'), builder:(context,snapshot){ if(snapshot.hasError) return Center(child: Text('Error: ${snapshot.error}')); if(!snapshot.hasData) return const Center(child:CircularProgressIndicator()); final docs=snapshot.data!.docs; if(docs.isEmpty) return const Center(child:Text('No locations available.')); return ListView.builder(padding: const EdgeInsets.all(16), itemCount: docs.length, itemBuilder:(context,index){ final d=docs[index].data(); return Card(child: ExpansionTile(leading: const Icon(Icons.map,color:Colors.purple), title: Text(d['name']??'Unknown Location'), subtitle: Text('${d['building']??'-'} | ${d['level']??'-'} | ${d['room']??'-'}'), children:[Padding(padding: const EdgeInsets.all(16), child: Text(d['directionText']??'No direction available.'))])); }); })); } }
